#!/usr/bin/env bash
# Idempotent SDR bench setup for the Gnosis in-room protocol69 path.
#
# Default mode is check-only: report the receiver/TX toolchain state without
# cloning or building. Use --build when this machine should materialize the
# ephemeral libiio Pluto toolchain expected by the runtime.

set -euo pipefail

MODE="check"
REBUILD="0"
PROBE_USB="0"
PROBE_LIBIIO="0"

LIBIIO_VERSION="${GNOSIS_LIBIIO_VERSION:-v0.25}"
LIBIIO_SRC="${GNOSIS_LIBIIO_SRC:-/tmp/libiio_build}"
LIBIIO_BUILD="${GNOSIS_LIBIIO_BUILD:-${LIBIIO_SRC}/build}"
PLUTO_URI="${GNOSIS_PLUTO_URI:-usb:0.5.5}"
# Track whether the operator pinned a URI. When pinned we honor it; otherwise the
# probe auto-discovers the Pluto's USB address (which varies per enumeration).
if [[ -n "${GNOSIS_PLUTO_URI:-}" ]]; then
  PLUTO_URI_EXPLICIT="1"
else
  PLUTO_URI_EXPLICIT="0"
fi

RED=$'\033[0;31m'
GREEN=$'\033[0;32m'
YELLOW=$'\033[1;33m'
BLUE=$'\033[0;34m'
NC=$'\033[0m'

usage() {
  cat <<EOF
setup-sdr-toolchain.sh [--check|--build|--print-env] [--rebuild] [--probe-usb] [--probe-libiio]

Checks or prepares the local SDR bench used by protocol69 app teleportation.

Modes:
  --check       Report RTL-SDR, SoapySDR, and libiio/Pluto readiness (default).
  --build       Clone/build libiio ${LIBIIO_VERSION} with USB backend and tests.
  --print-env   Print exports needed by libiio-backed Pluto tools.

Options:
  --rebuild     Reconfigure/rebuild even when libiio tools already exist.
  --probe-usb       Include a macOS USB device summary when available.
  --probe-libiio    Probe libiio contexts and auto-discover the Pluto URI.
  --probe-hardware  Alias for --probe-usb --probe-libiio.

Environment:
  GNOSIS_LIBIIO_VERSION   libiio branch/tag, default ${LIBIIO_VERSION}
  GNOSIS_LIBIIO_SRC       source checkout, default ${LIBIIO_SRC}
  GNOSIS_LIBIIO_BUILD     build directory, default ${LIBIIO_BUILD}
  GNOSIS_PLUTO_URI        pin the libiio URI; unset = auto-discover from the
                          iio_info -s scan (default ${PLUTO_URI} as last resort)
EOF
}

log_info() {
  echo "${BLUE}[sdr:info]${NC} $*"
}

log_success() {
  echo "${GREEN}[sdr:ok]${NC} $*"
}

log_warn() {
  echo "${YELLOW}[sdr:warn]${NC} $*" >&2
}

log_error() {
  echo "${RED}[sdr:error]${NC} $*" >&2
}

command_exists() {
  command -v "$1" >/dev/null 2>&1
}

resolve_command() {
  local name="$1"
  if command_exists "$name"; then
    command -v "$name"
    return 0
  fi

  local candidate
  for candidate in "/opt/homebrew/bin/${name}" "/usr/local/bin/${name}"; do
    if [[ -x "$candidate" ]]; then
      printf '%s\n' "$candidate"
      return 0
    fi
  done

  return 1
}

tool_status() {
  local label="$1"
  local name="$2"
  local path

  if path="$(resolve_command "$name")"; then
    log_success "${label}: ${path}"
  else
    log_warn "${label}: missing (${name})"
    return 1
  fi
}

libiio_tool_path() {
  local name="$1"
  printf '%s/tests/%s' "$LIBIIO_BUILD" "$name"
}

libiio_framework_path() {
  printf '%s/iio.framework/iio' "$LIBIIO_BUILD"
}

print_env() {
  cat <<EOF
export GNOSIS_LIBIIO_SRC="${LIBIIO_SRC}"
export GNOSIS_LIBIIO_BUILD="${LIBIIO_BUILD}"
export GNOSIS_PLUTO_URI="${PLUTO_URI}"
export DYLD_FALLBACK_FRAMEWORK_PATH="${LIBIIO_BUILD}\${DYLD_FALLBACK_FRAMEWORK_PATH:+:\${DYLD_FALLBACK_FRAMEWORK_PATH}}"
EOF
}

require_build_prereqs() {
  local missing=0

  if ! tool_status "git" "git"; then
    missing=1
  fi
  if ! tool_status "cmake" "cmake"; then
    missing=1
  fi

  if [[ "$missing" != "0" ]]; then
    log_error "libiio build requires git and cmake. Install them first, then rerun with --build."
    exit 1
  fi
}

build_libiio() {
  require_build_prereqs

  if [[ -x "$(libiio_tool_path iio_info)" && "$REBUILD" != "1" ]]; then
    log_success "libiio tools already built at ${LIBIIO_BUILD}"
    return
  fi

  if [[ ! -d "$LIBIIO_SRC" ]]; then
    log_info "cloning libiio ${LIBIIO_VERSION} into ${LIBIIO_SRC}"
    git clone --depth 1 --branch "$LIBIIO_VERSION" https://github.com/analogdevicesinc/libiio "$LIBIIO_SRC"
  elif [[ ! -d "${LIBIIO_SRC}/.git" ]]; then
    log_error "${LIBIIO_SRC} exists but is not a git checkout. Set GNOSIS_LIBIIO_SRC to another path or move the directory."
    exit 1
  else
    log_info "using existing libiio checkout at ${LIBIIO_SRC}"
  fi

  log_info "configuring libiio USB build at ${LIBIIO_BUILD}"
  cmake -S "$LIBIIO_SRC" -B "$LIBIIO_BUILD" \
    -DWITH_USB_BACKEND=ON \
    -DWITH_TESTS=ON \
    -DHAVE_DNS_SD=OFF

  log_info "building libiio"
  cmake --build "$LIBIIO_BUILD"
  log_success "libiio build ready at ${LIBIIO_BUILD}"
}

check_libiio() {
  local missing=0
  local framework
  framework="$(libiio_framework_path)"

  if [[ -x "$(libiio_tool_path iio_info)" ]]; then
    log_success "iio_info: $(libiio_tool_path iio_info)"
  else
    log_warn "iio_info missing at $(libiio_tool_path iio_info)"
    missing=1
  fi

  if [[ -x "$(libiio_tool_path iio_attr)" ]]; then
    log_success "iio_attr: $(libiio_tool_path iio_attr)"
  else
    log_warn "iio_attr missing at $(libiio_tool_path iio_attr)"
    missing=1
  fi

  if [[ -x "$(libiio_tool_path iio_writedev)" ]]; then
    log_success "iio_writedev: $(libiio_tool_path iio_writedev)"
  else
    log_warn "iio_writedev missing at $(libiio_tool_path iio_writedev)"
    missing=1
  fi

  if [[ -e "$framework" ]]; then
    log_success "libiio framework: ${framework}"
  else
    log_warn "libiio framework missing at ${framework}"
    missing=1
  fi

  if [[ "$missing" != "0" ]]; then
    log_warn "Pluto TX runtime expects libiio under ${LIBIIO_BUILD}; run this script with --build."
    return 1
  fi

  return 0
}

# Parse a Pluto USB URI out of `iio_info -s` output. The scan prints one line per
# context, e.g. `0: 0456:b673 (Analog Devices Inc. PlutoSDR ...) [usb:3.13.5]`.
# Prefer a Pluto-looking line; otherwise accept a lone USB context. Prints the
# discovered URI (or nothing) on stdout.
discover_pluto_uri() {
  local scan="$1"
  local uri unique

  # First choice: a context that names a Pluto / ADALM / Analog Devices device.
  uri="$(printf '%s\n' "$scan" \
    | grep -iE 'pluto|adalm|analog devices|0456:b673' \
    | grep -oE 'usb:[0-9]+\.[0-9]+\.[0-9]+' \
    | head -1)"
  if [[ -n "$uri" ]]; then
    printf '%s\n' "$uri"
    return 0
  fi

  # Fallback: if exactly one USB context exists, assume it is the Pluto.
  unique="$(printf '%s\n' "$scan" | grep -oE 'usb:[0-9]+\.[0-9]+\.[0-9]+' | sort -u)"
  if [[ -n "$unique" && "$(printf '%s\n' "$unique" | wc -l | tr -d ' ')" == "1" ]]; then
    printf '%s\n' "$unique"
    return 0
  fi

  # Ambiguous or empty: let the caller fall back to the configured URI.
  return 0
}

probe_libiio_devices() {
  local iio_info
  iio_info="$(libiio_tool_path iio_info)"

  if [[ ! -x "$iio_info" ]]; then
    return 0
  fi

  log_info "probing libiio contexts with iio_info -s"
  local scan_out
  if scan_out="$(DYLD_FALLBACK_FRAMEWORK_PATH="$LIBIIO_BUILD" "$iio_info" -s 2>&1)"; then
    printf '%s\n' "$scan_out"
  else
    printf '%s\n' "$scan_out"
    log_warn "iio_info -s failed; Pluto may be detached or the USB backend may be unavailable."
  fi

  # Auto-discover the Pluto URI from the scan; the USB address changes per
  # enumeration, so the hardcoded default is only a last resort.
  local discovered
  discovered="$(discover_pluto_uri "$scan_out")"
  if [[ -n "$discovered" ]]; then
    if [[ "$PLUTO_URI_EXPLICIT" == "1" && "$discovered" != "$PLUTO_URI" ]]; then
      log_info "discovered Pluto at ${discovered}; GNOSIS_PLUTO_URI pins ${PLUTO_URI}, honoring the pin"
    else
      PLUTO_URI="$discovered"
      log_success "auto-discovered Pluto URI: ${PLUTO_URI}"
    fi
  else
    log_info "no Pluto URI in scan; falling back to ${PLUTO_URI}"
  fi

  log_info "probing Pluto URI ${PLUTO_URI}"
  if ! DYLD_FALLBACK_FRAMEWORK_PATH="$LIBIIO_BUILD" "$iio_info" -u "$PLUTO_URI" >/tmp/gnosis-pluto-iio-info.txt 2>/tmp/gnosis-pluto-iio-info.err; then
    log_warn "Pluto not reachable at ${PLUTO_URI}; see /tmp/gnosis-pluto-iio-info.err"
    return 0
  fi

  head -40 /tmp/gnosis-pluto-iio-info.txt
  log_success "Pluto reachable at ${PLUTO_URI}"
}

probe_usb_summary() {
  if [[ "$PROBE_USB" != "1" ]]; then
    return
  fi

  if command_exists ioreg; then
    log_info "USB devices matching SDR vendor/product hints"
    ioreg -p IOUSB -w 0 | grep -Ei 'Pluto|ADALM|Analog Devices|RTL|RTL2838|NESDR|Nooelec|0x0456|0xb673' || true
  elif command_exists system_profiler; then
    log_info "USB devices matching SDR vendor/product hints"
    system_profiler SPUSBDataType | grep -Ei 'Pluto|ADALM|Analog Devices|RTL|NESDR|Nooelec' || true
  else
    log_warn "USB probe unavailable: neither ioreg nor system_profiler is on PATH"
  fi
}

check_receiver_tools() {
  tool_status "RTL-SDR capture" "rtl_sdr" || true
  tool_status "RTL-SDR probe" "rtl_test" || true
}

check_transmitter_tools() {
  tool_status "SoapySDR discovery" "SoapySDRUtil" || true
  check_libiio || true
}

run_check() {
  log_info "checking SDR toolchain"
  check_receiver_tools
  check_transmitter_tools
  if [[ "$PROBE_LIBIIO" == "1" ]]; then
    probe_libiio_devices
  fi
  probe_usb_summary
  log_info "Pluto environment exports:"
  print_env | sed 's/^/  /'
}

while [[ $# -gt 0 ]]; do
  case "$1" in
    --check)
      MODE="check"
      ;;
    --build)
      MODE="build"
      ;;
    --print-env)
      MODE="print-env"
      ;;
    --rebuild)
      REBUILD="1"
      ;;
    --probe-usb)
      PROBE_USB="1"
      ;;
    --probe-libiio)
      PROBE_LIBIIO="1"
      ;;
    --probe-hardware)
      PROBE_USB="1"
      PROBE_LIBIIO="1"
      ;;
    -h|--help)
      usage
      exit 0
      ;;
    *)
      log_error "unknown argument: $1"
      usage >&2
      exit 2
      ;;
  esac
  shift
done

case "$MODE" in
  check)
    run_check
    ;;
  build)
    build_libiio
    run_check
    ;;
  print-env)
    print_env
    ;;
  *)
    log_error "unknown mode: ${MODE}"
    exit 2
    ;;
esac
